    public function fetch_order_book(string $symbol, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $limit, $params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/orderbook
             *
             * fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
             * @param {string} $symbol unified $symbol of the $market to fetch the order book for
             * @param {int} [$limit] the maximum amount of order book entries to return
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} A dictionary of ~@link https://docs.ccxt.com/#/?id=order-book-structure order book structures~ indexed by $market symbols
             */
            Async\await($this->load_markets());
            $market = $this->market($symbol);
            $chId = $this->safe_string($market, 'id');
            $request = array(
                'chId' => $chId,
            );
            $response = Async\await($this->publicPostOrderbook ($this->extend($request, $params)));
            //
            // {
            //     "asks":[
            //         [76228.1534,11.58777]
            //     ],
            //     "bids":[
            //         [76213.4842,11.96145],
            //     ],
            //     "datetime":"2025-04-07 09:29:28.213 UTC",
            //     "timestamp":1744018168213,
            //     "symbol":"BTC/USD:USDC"
            // }
            //
            $timestamp = $this->safe_integer($response, 'timestamp');
            $orderbook = $this->parse_order_book($response, $symbol, $timestamp);
            $orderbook['nonce'] = $this->safe_integer($response, 'nonce');
            return $orderbook;
        }) ();
    }

    public function fetch_trades(string $symbol, ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/trades
             *
             * get the list of most recent trades for a particular $symbol
             * @param {string} $symbol unified $symbol of the $market to fetch trades for
             * @param {int} [$since] timestamp in ms of the earliest trade to fetch
             * @param {int} [$limit] the maximum amount of trades to fetch
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {int} [$params->until] the latest time in ms to fetch trades for
             * @return {Trade[]} a list of ~@link https://docs.ccxt.com/#/?id=public-trades trade structures~
             */
            Async\await($this->load_markets());
            $market = $this->market($symbol);
            $chId = $this->safe_string($market, 'id');
            $request = array(
                'chId' => $chId,
            );
            if ($limit !== null) {
                $request['limit'] = min ($limit, 50);
            }
            $response = Async\await($this->publicPostTrades ($this->extend($request, $params)));
            //
            //     {
            //         "trades" => array(
            //             {
            //                 "amount" => 0.03378,
            //                 "datetime" => "2025-12-29 22:43:54.639 UTC",
            //                 "price" => 87239.09499000001,
            //                 "timestamp" => 1767048234639,
            //                 "side" => "buy",
            //                 "symbol" => "BTC/USD:USDC"
            //             }
            //         ),
            //         "nextCursor" => 573
            //     }
            //
            $data = $this->safe_list($response, 'trades', array());
            return $this->parse_trades($data, $market, $since, $limit);
        }) ();
    }

    public function parse_trade(array $rawTrade, ?array $market = null): array {
        $trade = $this->safe_trade($this->extend(array( 'info' => $rawTrade ), $rawTrade));
        $trade['id'] = '';
        $trade['order'] = null;
        $trade['takerOrMaker'] = null;
        $trade['timestamp'] = $this->safe_integer($rawTrade, 'timestamp');
        return $trade;
    }

    public function fetch_ohlcv(string $symbol, $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($symbol, $timeframe, $since, $limit, $params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/ohlcv
             *
             * fetches historical candlestick data containing the open, high, low, and close price, and the volume of a $market
             * @param {string} $symbol unified $symbol of the $market to fetch OHLCV data for
             * @param {string} $timeframe the length of time each candle represents
             * @param {int} [$since] timestamp in ms of the earliest candle to fetch
             * @param {int} [$limit] max=1000, max=100 when $since is defined and is less than (now - (999 * (is_array(ms) && array_key_exists($timeframe, ms))))
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {int[][]} A list of candles ordered, open, high, low, close, volume
             */
            Async\await($this->load_markets());
            $market = $this->market($symbol);
            $chId = $this->safe_string($market, 'id');
            $request = array(
                'chId' => $chId,
                'timeframe' => $timeframe,
            );
            if ($since !== null) {
                $request['since'] = $since;
            }
            if ($limit !== null) {
                $request['limit'] = $limit;
            }
            $response = Async\await($this->publicPostOHLCV ($this->extend($request, $params)));
            //
            // array(
            //     array(
            //         1743932340000,
            //         83093.5445,
            //         83093.5445,
            //         83093.5445,
            //         83093.5445,
            //         0.0
            //     )
            // )
            //
            return $this->parse_ohlcvs($response, $market, $timeframe, $since, $limit);
        }) ();
    }

    public function fetch_balance($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/balance
             *
             * query for balance and get the amount of funds available for trading or funds locked in positions
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->account] $account object ID, required
             * @return {array} a ~@link https://docs.ccxt.com/#/?id=balance-structure balance structure~
             */
            $account = null;
            list($account, $params) = $this->handle_option_and_params($params, 'fetchBalance', 'account');
            $request = array(
                'account' => $account,
            );
            if ($account === null) {
                throw new ArgumentsRequired($this->id . ' fetchBalance() requires account');
            }
            $response = Async\await($this->privatePostBalance ($this->extend($request, $params)));
            //
            // {
            //     "timestamp" => 1744045700352,
            //     "balances" => {
            //         "USDC" => {
            //             "free" => 7.726913939320065,
            //             "used" => 22.273086060679937,
            //             "total" => 30.0
            //         }
            //     }
            // }
            //
            return $this->parse_balance($response);
        }) ();
    }

    public function parse_balance($response): array {
        $result = array(
            'info' => $response,
        );
        $balances = $this->safe_dict($response, 'balances', array());
        $currencies = is_array($balances) ? array_keys($balances) : array();
        for ($i = 0; $i < count($currencies); $i++) {
            $code = $currencies[$i];
            $balance = $balances[$code];
            $account = $this->account();
            $account['free'] = $this->safe_string($balance, 'free');
            $account['used'] = $this->safe_string($balance, 'used');
            $account['total'] = $this->safe_string($balance, 'total');
            $result[$code] = $account;
        }
        $timestamp = $this->safe_integer($response, 'timestamp');
        $result['timestamp'] = $timestamp;
        $result['datetime'] = $this->iso8601($timestamp);
        return $this->safe_balance($result);
    }

