    public function parse_create_edit_order_args(?string $id, string $symbol, string $type, string $side, float $amount, ?float $price = null, $params = array ()) {
        $market = $this->market($symbol);
        $symbol = $market['symbol'];
        $order = array(
            'symbol' => $symbol,
            'type' => $type,
            'side' => $side,
            'amount' => $amount,
            'price' => $price,
            'params' => $params,
        );
        if ($id !== null) {
            $order['id'] = $id;
        }
        return $order;
    }

    public function create_order(string $symbol, string $type, string $side, float $amount, ?float $price = null, $params = array ()) {
        return Async\async(function () use ($symbol, $type, $side, $amount, $price, $params) {
            /**
             * create a trade $order
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/build_create_orders
             * @see https://testnet.aftermath.finance/docs/#/CCXT/submit_create_orders
             *
             * @param {string} $symbol unified $symbol of the market to create an $order in
             * @param {string} $type 'market' or 'limit'
             * @param {string} $side 'buy' or 'sell'
             * @param {float} $amount how much of currency you want to trade in units of base currency
             * @param {float} [$price] the $price at which the $order is to be fulfilled, in units of the quote currency, ignored in market $orders
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {bool} [$params->reduceOnly] true or false whether the $order is reduce-only
             * @param {Account} [$params->account] $account id to use, required
             * @return {array} an ~@link https://docs.ccxt.com/#/?id=$order-structure $order structure~
             */
            Async\await($this->load_markets());
            $account = null;
            list($account, $params) = $this->handle_option_and_params($params, 'createOrder', 'account');
            $order = $this->parse_create_edit_order_args(null, $symbol, $type, $side, $amount, $price, $params);
            $orders = Async\await($this->create_orders(array( $order ), array( 'account' => $account )));
            return $orders[0];
        }) ();
    }

    public function create_orders(array $orders, $params = array ()): PromiseInterface {
        return Async\async(function () use ($orders, $params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/build_create_orders
             * @see https://testnet.aftermath.finance/docs/#/CCXT/submit_create_orders
             *
             * create a list of trade $orders
             * @param {Array} $orders list of $orders to create, each object should contain the parameters required by createOrder, namely $symbol, type, side, $amount, $price and $params
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {Account} [$params->account] $account id to use, required
             * @return {array} an ~@link https://docs.ccxt.com/#/?id=$order-structure $order structure~
             */
            Async\await($this->load_markets());
            $ordersRequest = array();
            for ($i = 0; $i < count($orders); $i++) {
                $order = $this->clone($orders[$i]);
                $symbol = $this->safe_string($order, 'symbol');
                $market = $this->market($symbol);
                $price = $this->safe_string($order, 'price');
                $amount = $this->safe_string($order, 'amount');
                $orderParams = $this->safe_dict($order, 'params', array());
                $reduceOnly = $this->safe_bool($orderParams, 'reduceOnly');
                if ($reduceOnly !== null) {
                    $order['reduceOnly'] = $reduceOnly;
                }
                unset($order['symbol']);
                unset($order['params']);
                $order['chId'] = $market['id'];
                if ($price !== null) {
                    $order['price'] = $this->parse_to_numeric($this->price_to_precision($symbol, $price));
                }
                $order['amount'] = $this->parse_to_numeric($this->amount_to_precision($symbol, $amount));
                $ordersRequest[] = $order;
            }
            $account = null;
            list($account, $params) = $this->handle_option_and_params($params, 'createOrders', 'account');
            $txRequest = array(
                'accountId' => $account,
                'metadata' => array(
                    'sender' => $this->walletAddress,
                ),
                'orders' => $ordersRequest,
                'deallocateFreeCollateral' => false,
            );
            $tx = Async\await($this->privatePostBuildCreateOrders ($this->extend($txRequest, $params)));
            $request = $this->sign_tx_ed25519($tx);
            $response = Async\await($this->privatePostSubmitCreateOrders ($request));
            //
            // array(
            //     {
            //         "id" => "340282366919093604570116171100942992979",
            //         "datetime" => "2025-04-10 10:38:39.323 UTC",
            //         "timestamp" => 1744281519323,
            //         "status" => "open",
            //         "symbol" => "BTC/USD:USDC",
            //         "type" => "limit",
            //         "side" => "buy",
            //         "price" => 10001.0,
            //         "average" => 0.0,
            //         "amount" => 0.01,
            //         "filled" => 0.0,
            //         "remaining" => 0.01,
            //         "cost" => 0.0,
            //         "trades" => array(),
            //         "fee" => array()
            //     }
            // )
            //
            return $this->parse_orders($response);
        }) ();
    }

