    public function withdraw(string $code, float $amount, string $address, ?string $tag = null, $params = array ()): PromiseInterface {
        return Async\async(function () use ($code, $amount, $address, $tag, $params) {
            /**
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/build_withdraw
             * @see https://testnet.aftermath.finance/docs/#/CCXT/submit_withdraw
             *
             * make a withdrawal
             * @param {string} $code unified $currency $code
             * @param {float} $amount the $amount to withdraw
             * @param {string} $address the $address to withdraw to
             * @param {string} $tag
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {Account} [$params->account] $account id to use, required
             * @return {array} a ~@link https://docs.ccxt.com/#/?id=transaction-structure transaction structure~
             */
            Async\await($this->load_markets());
            $currency = $this->currency($code);
            $account = null;
            list($account, $params) = $this->handle_option_and_params($params, 'withdraw', 'account');
            if ($account === null) {
                throw new ArgumentsRequired($this->id . ' withdraw() requires a $account parameter in params');
            }
            $txRequest = array(
                'accountId' => $account,
                'metadata' => array(
                    'sender' => $this->walletAddress,
                ),
                'amount' => $amount,
            );
            $tx = Async\await($this->privatePostBuildWithdraw ($txRequest));
            $request = $this->sign_tx_ed25519($tx);
            $response = Async\await($this->privatePostSubmitWithdraw ($request));
            //
            // {
            //     "id" => "0xf93f9bb8bf97eb570410caada92cfa3e66c7ed3a203a164f51d22d41eabe09c0",
            //     "type" => "subaccount",
            //     "code" => "USDC",
            //     "accountNumber" => 101,
            //     "collateral" => 39.0
            // }
            //
            return $this->extend($this->parse_transaction($response, $currency), array(
                'addressFrom' => $account,
                'amount' => $amount,
            ));
        }) ();
    }

    public function parse_transaction(array $transaction, ?array $currency = null): array {
        return array(
            'info' => $transaction,
            'id' => $this->safe_string($transaction, 'id'),
            'txid' => $this->safe_string($transaction, 'tx_id'),
            'timestamp' => null,
            'datetime' => null,
            'address' => null,
            'addressFrom' => null,
            'addressTo' => null,
            'tag' => null,
            'tagFrom' => null,
            'tagTo' => null,
            'type' => null,
            'amount' => null,
            'currency' => $this->safe_string($transaction, 'code'),
            'status' => null,
            'updated' => null,
            'comment' => null,
            'internal' => null,
            'fee' => null,
            'network' => null,
        );
    }

    public function set_leverage(int $leverage, ?string $symbol = null, $params = array ()) {
        return Async\async(function () use ($leverage, $symbol, $params) {
            /**
             * set the level of $leverage for a $market
             *
             * @see https://testnet.aftermath.finance/docs/#/CCXT/build_set_leverage
             * @see https://testnet.aftermath.finance/docs/#/CCXT/submit_set_leverage
             *
             * @param {float} $leverage the rate of $leverage
             * @param {string} $symbol unified $market $symbol
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {Account} [$params->account] $account id to use, required
             * @return {array} $response from the exchange
             */
            if ($symbol === null) {
                throw new ArgumentsRequired($this->id . ' setLeverage() requires a $symbol argument');
            }
            Async\await($this->load_markets());
            $market = $this->market($symbol);
            $account = null;
            list($account, $params) = $this->handle_option_and_params_2($params, 'setLeverage', 'account', 'accountId');
            $txRequest = array(
                'accountId' => $account,
                'chId' => $market['id'],
                'leverage' => $leverage,
                'metadata' => array(
                    'sender' => $this->walletAddress,
                ),
            );
            $tx = Async\await($this->privatePostBuildSetLeverage ($txRequest));
            $request = $this->sign_tx_ed25519($tx);
            $response = Async\await($this->privatePostSubmitSetLeverage ($request));
            //
            // {
            //     "id" => "0xyydsxxxxxxxxyydsxxxxxxx:141",
            //     "symbol" => "BTC/USD:USDC",
            //     "marginMode" => "isolated",
            //     "side" => "long",
            //     "contracts" => 0.001,
            //     "contractSize" => 88506.195911625,
            //     "entryPrice" => 90999.0,
            //     "notional" => 88.50907726931732,
            //     "marginRatio" => 1.0000000000041465,
            //     "leverage" => 0.9999999999958537,
            //     "collateral" => 91.00196251238035,
            //     "initialMargin" => 2.212726931732933,
            //     "maintenanceMargin" => 1.1063634658664665,
            //     "initialMarginPercentage" => 0.025,
            //     "maintenanceMarginPercentage" => 0.0125,
            //     "unrealizedPnl" => -2.492804088375008,
            //     "liquidationPrice" => -3.71625538227e-7
            // }
            //
            return $response;
        }) ();
    }

    public function sign_tx_ed25519(array $tx): array {
        /**
         * Helper to sign some transaction bytes and return a generic transaction execution request.
         * @param {array} [$tx] transaction bytes and the signing $digest for them
         * @return {array} the input transaction bytes and the signed $digest
         */
        if (mb_strpos($this->privateKey, 'suiprivkey') !== false) {
            throw new NotSupported($this->id . ' only support hex encoding private key, please transform bech32 encoding private key');
        }
        $signingDigest = $this->safe_string($tx, 'signingDigest');
        $digest = base64_decode($signingDigest);
        $privateKey = $this->base16_to_binary($this->privateKey);
        $signature = $this->eddsa($digest, $privateKey, 'ed25519');
        $hexPublicKey = $this->safe_string($this->options, 'publicKey');
        if ($hexPublicKey === null) {
            throw new ArgumentsRequired($this->id . ' requires hex encoding public key in options');
        }
        $publicKey = $this->base16_to_binary($hexPublicKey);
        $suiSignature = $this->binary_concat($this->base16_to_binary('00'), $this->binary_concat(base64_decode($signature), $publicKey));
        $base64Sig = $this->binary_to_base64($suiSignature);
        $transactionBytes = $this->safe_string($tx, 'transactionBytes');
        $signatures = array( $base64Sig );
        return array( 'transactionBytes' => $transactionBytes, 'signatures' => $signatures );
    }

    public function parse_order(array $order, ?array $market = null): array {
        return $this->safe_order($order, $market);
    }

    public function handle_errors(int $httpCode, string $reason, string $url, string $method, array $headers, string $body, $response, $requestHeaders, $requestBody) {
        if (!$response) {
            return null; // fallback to default error handler
        }
        //
        // Error with ID => #68498f1e536664f31a7b1aa7
        //
        if (mb_strpos($body, 'Error') !== false) {
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $body, '');
            throw new ExchangeError($body);
        }
        return null;
    }

    public function sign($path, $api = 'public', $method = 'POST', $params = array (), $headers = null, $body = null) {
        $url = $this->urls['api']['rest'] . '/' . $path;
        if ($api === 'private') {
            $this->check_required_credentials();
        }
        if ($method === 'POST') {
            $headers = array(
                'Content-Type' => 'application/json',
            );
            $body = $this->json($params);
        }
        return array( 'url' => $url, 'method' => $method, 'body' => $body, 'headers' => $headers );
    }
}
